patch:
diff --git a/llvm/lib/Target/AArch64/AArch64TargetTransformInfo.cpp b/llvm/lib/Target/AArch64/AArch64TargetTransformInfo.cpp
index 58c267f1ce4b..82fc64ec3d0f 100644
--- a/llvm/lib/Target/AArch64/AArch64TargetTransformInfo.cpp
+++ b/llvm/lib/Target/AArch64/AArch64TargetTransformInfo.cpp
@@ -550,7 +550,18 @@ AArch64TTIImpl::getIntrinsicInstrCost(const IntrinsicCostAttributes &ICA,
     if (VTy->getElementCount() == ElementCount::getScalable(1))
       return InstructionCost::getInvalid();

+  if (const auto *CI = ICA.getInst()) {
+    if (const Function *F = CI->getCalledFunction()) {
+      // The powi intrinsic can be called as a function, so check for it by
+      // name.
+      if (F->getName().starts_with("llvm.powi"))
+        return TTI::TCC_Expensive;
+    }
+  }
   switch (ICA.getID()) {
+  case Intrinsic::powi:
+    return TTI::TCC_Expensive;
+
   case Intrinsic::experimental_vector_histogram_add:
     if (!ST->hasSVE2())
       return InstructionCost::getInvalid();

